<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>WastedToken Mint — Collectible Challenge Coins</title>
<style>
  :root{
    --bg:#07090e;
    --bg2:#0c1018;
    --panel:#10151f;
    --line:#1e2635;
    --ink:#e8e4d8;
    --ink-dim:#9aa0ad;
    --gold:#d8a94e;
    --gold-bright:#f3cd7d;
    --serif:Georgia,"Times New Roman",serif;
    --sans:"Segoe UI",system-ui,-apple-system,sans-serif;
  }
  *{margin:0;padding:0;box-sizing:border-box}
  html{scroll-behavior:smooth}
  body{
    background:var(--bg);
    color:var(--ink);
    font-family:var(--sans);
    line-height:1.6;
    overflow-x:hidden;
  }
  ::selection{background:var(--gold);color:#111}

  /* ---------- header ---------- */
  header{
    position:sticky;top:0;z-index:50;
    display:flex;align-items:center;justify-content:space-between;
    padding:18px 40px;
    background:rgba(7,9,14,.82);
    backdrop-filter:blur(10px);
    border-bottom:1px solid var(--line);
  }
  .wordmark{
    font-family:var(--serif);
    font-size:20px;letter-spacing:.14em;
    color:var(--gold-bright);
    text-transform:uppercase;
    display:flex;align-items:center;gap:12px;
    text-decoration:none;
  }
  .wordmark .seal{
    width:30px;height:30px;border-radius:50%;
    border:2px solid var(--gold);
    display:grid;place-items:center;
    font-size:14px;font-weight:700;color:var(--gold);
    background:radial-gradient(circle at 35% 30%, #2a2010, #100b04);
  }
  nav a{
    color:var(--ink-dim);text-decoration:none;
    font-size:13px;letter-spacing:.18em;text-transform:uppercase;
    margin-left:34px;transition:color .25s;
  }
  nav a:hover{color:var(--gold-bright)}

  /* ---------- hero ---------- */
  .hero{
    max-width:1180px;margin:0 auto;
    display:grid;grid-template-columns:1fr 1fr;
    align-items:center;gap:48px;
    padding:70px 40px 90px;
    min-height:78vh;
  }
  .hero-copy .kicker{
    color:var(--gold);font-size:12px;letter-spacing:.34em;
    text-transform:uppercase;margin-bottom:22px;
    display:flex;align-items:center;gap:14px;
  }
  .kicker::before{content:"";display:block;width:44px;height:1px;background:var(--gold)}
  .hero-copy h1{
    font-family:var(--serif);
    font-size:clamp(42px,5.2vw,66px);
    line-height:1.06;font-weight:700;
    letter-spacing:.01em;
  }
  .hero-copy h1 em{
    font-style:normal;
    background:linear-gradient(100deg,#8a6522,#f3cd7d 45%,#b98a35 70%,#f8e3ae);
    -webkit-background-clip:text;background-clip:text;color:transparent;
  }
  .hero-copy p{
    margin-top:24px;color:var(--ink-dim);font-size:17px;max-width:46ch;
  }
  .hero-cta{margin-top:38px;display:flex;gap:16px;flex-wrap:wrap}
  .btn{
    display:inline-block;padding:14px 30px;
    font-size:13px;letter-spacing:.22em;text-transform:uppercase;
    text-decoration:none;cursor:pointer;border-radius:2px;
    transition:transform .2s, box-shadow .2s, background .2s;
    font-family:var(--sans);
  }
  .btn-gold{
    background:linear-gradient(120deg,#b98a35,#f3cd7d 50%,#b98a35);
    color:#191104;border:none;font-weight:700;
  }
  .btn-gold:hover{transform:translateY(-2px);box-shadow:0 10px 30px rgba(216,169,78,.28)}
  .btn-ghost{
    background:transparent;color:var(--ink);
    border:1px solid var(--line);
