  .hero-stage{position:relative;display:grid;place-items:center}
  #coin-hero{
    width:min(100%,560px);aspect-ratio:1/1;height:auto;
    display:block;border-radius:14px;
    box-shadow:0 30px 90px rgba(0,0,0,.6), 0 0 0 1px var(--line);
