  .stage-caption{
    position:absolute;bottom:-34px;left:50%;transform:translateX(-50%);
    font-size:11px;letter-spacing:.3em;text-transform:uppercase;
    color:var(--ink-dim);white-space:nowrap;
  }

  /* ---------- stats strip ---------- */
  .stats{
    border-top:1px solid var(--line);border-bottom:1px solid var(--line);
    background:var(--bg2);
  }
  .stats-inner{
    max-width:1180px;margin:0 auto;padding:26px 40px;
    display:grid;grid-template-columns:repeat(3,1fr);gap:24px;text-align:center;
  }
  .stat b{
    display:block;font-family:var(--serif);font-size:30px;
    color:var(--gold-bright);letter-spacing:.02em;
  }
  .stat span{font-size:12px;letter-spacing:.22em;text-transform:uppercase;color:var(--ink-dim)}

  /* ---------- sections ---------- */
  section.block{max-width:1180px;margin:0 auto;padding:96px 40px}
