    padding:18px 0;border-bottom:1px solid var(--line);
    display:flex;gap:18px;align-items:baseline;
  }
  .craft-list li:first-child{border-top:1px solid var(--line)}
  .craft-list .num{
    font-family:var(--serif);color:var(--gold);font-size:15px;min-width:34px;
  }
  .craft-list b{display:block;font-size:15px;letter-spacing:.04em}
  .craft-list small{color:var(--ink-dim);font-size:13.5px}

  /* ---------- collection ---------- */
  .grid{
    display:grid;grid-template-columns:repeat(4,1fr);gap:22px;
  }
  .edition{
    position:relative;
    background:linear-gradient(180deg,var(--panel),#0b0f17);
    border:1px solid var(--line);border-radius:10px;
    padding:20px 20px 24px;
    display:flex;flex-direction:column;gap:0;
    transition:transform .3s, border-color .3s, box-shadow .3s;
  }
  .edition[data-state="available"]:hover{
    transform:translateY(-6px);border-color:rgba(216,169,78,.55);
    box-shadow:0 24px 50px rgba(0,0,0,.5);
  }
  .edition-canvas{
    width:100%;aspect-ratio:1/1;height:auto;display:block;
    border-radius:8px;background:#0a0d13;
  }
  .edition h3{
    font-family:var(--serif);font-size:21px;margin-top:18px;letter-spacing:.02em;
  }
  .edition .denom{
    font-size:12px;letter-spacing:.24em;text-transform:uppercase;
    color:var(--gold);margin-top:5px;
  }
  .edition .meta{
    font-size:13.5px;color:var(--ink-dim);margin-top:10px;min-height:42px;
  }
  .edition .price{
    font-family:var(--serif);font-size:19px;color:var(--ink);margin-top:8px;
  }
  .badge{
    position:absolute;top:30px;left:30px;z-index:2;
    font-size:10.5px;font-weight:700;letter-spacing:.2em;text-transform:uppercase;
    padding:6px 11px;border-radius:3px;
  }
  .badge.avail{background:rgba(46,160,90,.16);color:#7fd8a2;border:1px solid rgba(63,178,106,.4)}
  .badge.sold{background:rgba(190,60,60,.16);color:#f19a9a;border:1px solid rgba(206,84,84,.45)}
  .badge.soon{background:rgba(120,130,220,.14);color:#aeb6f2;border:1px solid rgba(130,140,225,.4)}
  button.buy{
    margin-top:16px;padding:13px 10px;width:100%;
    font-size:12px;font-weight:700;letter-spacing:.22em;text-transform:uppercase;
    background:linear-gradient(120deg,#b98a35,#f3cd7d 50%,#b98a35);
