  button.buy:hover{transform:translateY(-2px);box-shadow:0 10px 26px rgba(216,169,78,.3)}
  .no-buy{
    margin-top:16px;padding:13px 10px;width:100%;text-align:center;
    font-size:12px;font-weight:700;letter-spacing:.22em;text-transform:uppercase;
    border:1px dashed var(--line);border-radius:3px;color:var(--ink-dim);
    user-select:none;
  }
  .edition[data-state="sold-out"] .edition-canvas{
    filter:grayscale(.55) brightness(.72) contrast(.95);
  }
  .edition[data-state="sold-out"]{border-style:dashed;opacity:.92}
  .edition[data-state="coming-soon"] .edition-canvas{filter:brightness(.9)}
  .ribbon{
    position:absolute;top:44px;right:-42px;z-index:3;
    transform:rotate(35deg);
    background:#8f2f2f;color:#ffe3e3;
    font-size:11px;font-weight:800;letter-spacing:.24em;
    padding:6px 48px;box-shadow:0 4px 14px rgba(0,0,0,.5);
