<script>
(function(){
'use strict';

/* ============================================================
   Face heightmap textures (procedural, deterministic)
   White = raised relief, black = field.
   ============================================================ */
function faceCanvas(){
  var c = document.createElement('canvas');
  c.width = c.height = 512;
  return c;
}
function ringText(x, str, r, a0, a1, font, flip){
  x.font = font; x.textAlign = 'center'; x.textBaseline = 'middle';
  var n = str.length;
  for (var i = 0; i < n; i++){
    var f = n === 1 ? 0.5 : (i + 0.5) / n;
    var a = a0 + (a1 - a0) * f;
    x.save();
    x.translate(256 + r * Math.cos(a), 256 + r * Math.sin(a));
    x.rotate(a + (flip ? -Math.PI/2 : Math.PI/2));
    x.fillText(str[i], 0, 0);
    x.restore();
  }
}
function beads(x){
  for (var i = 0; i < 60; i++){
    var a = i / 60 * Math.PI * 2;
    x.beginPath();
    x.arc(256 + 204 * Math.cos(a), 256 + 204 * Math.sin(a), 4, 0, Math.PI * 2);
    x.fill();
  }
}
function makeFront(){
  var c = faceCanvas(), x = c.getContext('2d');
  x.fillStyle = '#000'; x.fillRect(0, 0, 512, 512);
  x.fillStyle = '#fff'; x.strokeStyle = '#fff';
  x.shadowColor = '#fff'; x.shadowBlur = 5;
  beads(x);
  x.lineWidth = 4; x.beginPath(); x.arc(256,256,132,0,Math.PI*2); x.stroke();
  x.lineWidth = 2; x.beginPath(); x.arc(256,256,122,0,Math.PI*2); x.stroke();
  ringText(x, 'WASTEDTOKEN MINT', 170, -Math.PI/2 - 1.35, -Math.PI/2 + 1.35,
           'bold 34px Georgia, serif');
  ringText(x, '\u2605 CHALLENGE COINAGE \u2605', 172, Math.PI/2 + 1.1, Math.PI/2 - 1.1,
           'bold 25px Georgia, serif', true);
  x.textAlign = 'center'; x.textBaseline = 'middle';
  x.font = '900 146px Georgia, serif';
  x.fillText('W', 256, 244);
  x.font = 'bold 30px Georgia, serif';
  x.fillText('MMXXI', 256, 328);
  // small star above monogram
  x.save(); x.translate(256, 162); x.beginPath();
  for (var i = 0; i < 10; i++){
    var rr = (i % 2 === 0) ? 11 : 4.5;
    var a = -Math.PI/2 + i * Math.PI/5;
    if (i === 0) x.moveTo(rr*Math.cos(a), rr*Math.sin(a));
    else x.lineTo(rr*Math.cos(a), rr*Math.sin(a));
  }
  x.closePath(); x.fill(); x.restore();
  return c;
}
function leaf(x, cx, cy, ang){
  x.save(); x.translate(cx, cy); x.rotate(ang);
  x.beginPath(); x.ellipse(0, 0, 16, 6, 0, 0, Math.PI * 2); x.fill();
  x.restore();
}
function makeBack(){
  var c = faceCanvas(), x = c.getContext('2d');
  x.fillStyle = '#000'; x.fillRect(0, 0, 512, 512);
  x.fillStyle = '#fff'; x.strokeStyle = '#fff';
  x.shadowColor = '#fff'; x.shadowBlur = 5;
  beads(x);
  ringText(x, 'WASTEDTOKEN MINT', 176, -Math.PI/2 - 1.15, -Math.PI/2 + 1.15,
           'bold 28px Georgia, serif');
  ringText(x, 'FIRST STRIKE \u00B7 MMXXVI', 176, Math.PI/2 + 1.0, Math.PI/2 - 1.0,
           'bold 24px Georgia, serif', true);
  x.textAlign = 'center'; x.textBaseline = 'middle';
  x.fillRect(256 - 125, 172, 250, 3);
  x.fillRect(256 - 125, 336, 250, 3);
  x.font = '900 82px Georgia, serif';
  x.fillText('10,000', 256, 246);
  x.font = 'bold 40px Georgia, serif';
  x.fillText('T O K E N S', 256, 306);
  // laurel branches, left and right
  for (var i = 0; i < 8; i++){
    var aL = Math.PI * 0.72 + i * 0.078;       // left side sweeping down
    leaf(x, 256 + 150*Math.cos(aL), 256 + 150*Math.sin(aL), aL + Math.PI/2);
    var aR = Math.PI * 0.28 - i * 0.078;       // right side sweeping down
    leaf(x, 256 + 150*Math.cos(aR), 256 + 150*Math.sin(aR), aR + Math.PI/2);
  }
  return c;
}
var frontCanvas = makeFront();
var backCanvas  = makeBack();

/* ============================================================
   WebGL raymarched coin renderer
   ============================================================ */
var VS = 'attribute vec2 aP; void main(){ gl_Position = vec4(aP, 0.0, 1.0); }';

var FS = [
'precision highp float;',
'uniform vec2 uRes;',
'uniform mat3 uRot;',        // local -> world rotation
'uniform vec3 uTint;',
'uniform sampler2D uFront;',
'uniform sampler2D uBack;',
'const float HT = 0.085;',   // half thickness
'',
'float faceH(vec3 p){',
'  float r = length(p.xy);',
'  float h = 0.0;',
'  if (r < 0.90){',
'    vec2 uv = vec2(p.z >= 0.0 ? p.x : -p.x, p.y) * 0.5 + 0.5;',
'    float s = (p.z >= 0.0) ? texture2D(uFront, uv).r : texture2D(uBack, uv).r;',
'    h = s * 0.048 * smoothstep(0.90, 0.86, r);',
'  }',
'  float rim = (smoothstep(0.845, 0.885, r) - smoothstep(0.940, 0.972, r)) * 0.050;',
'  return max(h, rim);',
'}',
'',
'float map(vec3 p){',
'  float r = length(p.xy);',
'  float ang = atan(p.y, p.x);',
'  float reed = 0.013 * (0.5 + 0.5 * cos(ang * 72.0));',   // 72-ridge reeded edge
'  float dr = r - (0.965 + reed);',
'  float dz = abs(p.z) - (HT + faceH(p));',
'  vec2 w = vec2(dr, dz) + 0.018;',
'  return min(max(w.x, w.y), 0.0) + length(max(w, vec2(0.0))) - 0.018;',
'}',
'',
'vec3 calcN(vec3 p){',
'  float e = 0.0035;',
'  return normalize(vec3(',
'    map(p + vec3(e,0.0,0.0)) - map(p - vec3(e,0.0,0.0)),',
'    map(p + vec3(0.0,e,0.0)) - map(p - vec3(0.0,e,0.0)),',
'    map(p + vec3(0.0,0.0,e)) - map(p - vec3(0.0,0.0,e))));',
'}',
'',
'void main(){',
'  vec2 q = (gl_FragCoord.xy * 2.0 - uRes) / uRes.y;',
'  vec3 ro = vec3(0.0, 0.0, 3.4);',
'  vec3 rd = normalize(vec3(q, -1.9));',
'',
'  float vr = length(q);',
'  vec3 col = mix(vec3(0.075,0.083,0.108), vec3(0.026,0.030,0.043), smoothstep(0.1, 1.15, vr));',
'  col += vec3(0.10,0.082,0.048) * (1.0 - smoothstep(0.0, 0.95, vr)) * 0.32;',
'',
'  float b = dot(-ro, rd);',
'  float c2 = dot(ro, ro) - b * b;',
'  float R2 = 1.5625;',                       // bounding sphere r = 1.25
'  if (c2 < R2){',
'    float half_ = sqrt(R2 - c2);',
'    vec3 rol = ro * uRot;',                  // world -> local (multiply by transpose)
'    vec3 rdl = rd * uRot;',
'    float t = max(b - half_, 0.0);',
'    float tEnd = b + half_ + 0.1;',
'    float hit = -1.0;',
'    for (int i = 0; i < 128; i++){',
'      vec3 p = rol + rdl * t;',
'      float d = map(p);',
'      if (d < 0.0012){ hit = t; break; }',
'      t += d * 0.55;',
'      if (t > tEnd) break;',
'    }',
'    if (hit > 0.0){',
'      vec3 pl = rol + rdl * hit;',
'      vec3 n  = uRot * calcN(pl);',          // normal back to world space
'      vec3 v  = -rd;',
'      vec3 L1 = normalize(vec3(-0.5, 0.8, 0.6));',
'      vec3 L2 = normalize(vec3(0.8, -0.35, 0.45));',
'      vec3 h1 = normalize(L1 + v);',
'      vec3 h2 = normalize(L2 + v);',
'      float dif = 0.32 * max(dot(n, L1), 0.0) + 0.20 * max(dot(n, L2), 0.0) + 0.17;',
'      vec3 rr = reflect(rd, n);',
'      float env = 0.30 + 0.60 * smoothstep(-0.5, 0.9, rr.y)',
'                + 0.40 * pow(max(rr.y, 0.0), 3.0)',
'                + 0.18 * smoothstep(0.4, 1.0, rr.x);',
'      float s1 = pow(max(dot(n, h1), 0.0), 48.0);',
'      float s2 = pow(max(dot(n, h1), 0.0), 420.0);',
'      float s3 = pow(max(dot(n, h2), 0.0), 90.0);',
'      float fres = pow(1.0 - max(dot(n, v), 0.0), 4.0);',
'      col = uTint * (dif + env * 0.55)',
'          + mix(uTint, vec3(1.0), 0.5) * (s1 * 0.95 + s3 * 0.45)',
'          + vec3(1.0) * s2 * 1.35',
'          + uTint * fres * 0.9;',
'      col = col / (1.0 + col * 0.35);',
'    }',
'  }',
'  col = pow(max(col, vec3(0.0)), vec3(0.4545));',
'  gl_FragColor = vec4(col, 1.0);',
'}'
].join('\n');

function createRenderer(canvas){
  var gl = canvas.getContext('webgl', { antialias: true, preserveDrawingBuffer: true }) ||
           canvas.getContext('experimental-webgl', { antialias: true, preserveDrawingBuffer: true });
  if (!gl) return null;

  function sh(type, src){
    var s = gl.createShader(type);
    gl.shaderSource(s, src); gl.compileShader(s);
    return s;
  }
  var prog = gl.createProgram();
  gl.attachShader(prog, sh(gl.VERTEX_SHADER, VS));
  gl.attachShader(prog, sh(gl.FRAGMENT_SHADER, FS));
  gl.linkProgram(prog);
  gl.useProgram(prog);

  var buf = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, buf);
  gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-1,-1, 3,-1, -1,3]), gl.STATIC_DRAW);
  var loc = gl.getAttribLocation(prog, 'aP');
  gl.enableVertexAttribArray(loc);
  gl.vertexAttribPointer(loc, 2, gl.FLOAT, false, 0, 0);

  function tex(src, unit){
    var t = gl.createTexture();
    gl.activeTexture(gl.TEXTURE0 + unit);
    gl.bindTexture(gl.TEXTURE_2D, t);
    gl.pixelStorei(gl.UNPACK_FLIP_Y_WEBGL, true);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.LUMINANCE, gl.LUMINANCE, gl.UNSIGNED_BYTE, src);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
    return t;
  }
  tex(frontCanvas, 0);
  tex(backCanvas, 1);

  var uRes  = gl.getUniformLocation(prog, 'uRes');
  var uRot  = gl.getUniformLocation(prog, 'uRot');
  var uTint = gl.getUniformLocation(prog, 'uTint');
  gl.uniform1i(gl.getUniformLocation(prog, 'uFront'), 0);
  gl.uniform1i(gl.getUniformLocation(prog, 'uBack'), 1);

  return {
    render: function(rot, tint){
      gl.viewport(0, 0, canvas.width, canvas.height);
      gl.uniform2f(uRes, canvas.width, canvas.height);
      gl.uniformMatrix3fv(uRot, false, rot);
      gl.uniform3f(uTint, tint[0], tint[1], tint[2]);
      gl.drawArrays(gl.TRIANGLES, 0, 3);
    }
  };
}

/* Orientation for loop position t in [0,1]:
   full spin about vertical (Y) axis + flip/tumble about horizontal (X) axis.
   R = Rx(pitch) * Ry(yaw), column-major. Deterministic in t. */
function rotFor(t){
  var yaw = t * Math.PI * 2.0;
  var pitch = 0.16 + 0.66 * Math.sin(t * Math.PI * 2.0);
  var cy = Math.cos(yaw), sy = Math.sin(yaw);
  var cx = Math.cos(pitch), sx = Math.sin(pitch);
  return new Float32Array([
     cy,      sx * sy, -cx * sy,
     0.0,     cx,       sx,
     sy,     -sx * cy,  cx * cy
  ]);
}

/* ============================================================
   Hero coin
   ============================================================ */
var HERO_TINT = [0.95, 0.64, 0.24];
var heroCanvas = document.getElementById('coin-hero');
var hero = createRenderer(heroCanvas);
var paused = false;
var heroRAF = 0;

function renderHeroAt(t){
  if (hero) hero.render(rotFor(t), HERO_TINT);
}
function heroLoop(now){
  renderHeroAt((now / 9000) % 1);
  heroRAF = requestAnimationFrame(heroLoop);
}
renderHeroAt(0);
heroRAF = requestAnimationFrame(heroLoop);

/* ============================================================
   Edition coins — one shared offscreen GL renderer,
   blitted into each tile's 2D canvas.
   ============================================================ */
var TINTS = {
  bronze: [0.62, 0.36, 0.18],
  silver: [0.68, 0.72, 0.78],
  gold:   [0.98, 0.66, 0.20],
  black:  [0.055, 0.06, 0.078]
};
var off = document.createElement('canvas');
off.width = off.height = 384;
var offR = createRenderer(off);
var tiles = [];
var edEls = document.querySelectorAll('.edition');
for (var i = 0; i < edEls.length; i++){
  var el = edEls[i];
  var cv = el.querySelector('.edition-canvas');
  tiles.push({
    ctx: cv.getContext('2d'),
    tint: TINTS[el.getAttribute('data-edition')] || HERO_TINT,
    phase: i * 0.25
  });
}
var edRAF = 0, lastEd = -1e9;
function edLoop(now){
  if (now - lastEd > 33){                    // ~30 fps
    lastEd = now;
    for (var i = 0; i < tiles.length; i++){
      var tl = tiles[i];
      if (offR){
        offR.render(rotFor((now / 22000 + tl.phase) % 1), tl.tint);
        tl.ctx.drawImage(off, 0, 0, 384, 384);
      }
    }
  }
  edRAF = requestAnimationFrame(edLoop);
}
edRAF = requestAnimationFrame(edLoop);

/* ============================================================
   Programmatic API for grading
   ============================================================ */
window.demo = {
  canvas: heroCanvas,
  setTime: function(t){
    t = Number(t);
    if (!isFinite(t)) t = 0;
    t = ((t % 1) + 1) % 1;
    renderHeroAt(t);                          // synchronous, deterministic in t
  },
  pause: function(){
    paused = true;
    cancelAnimationFrame(heroRAF);
    cancelAnimationFrame(edRAF);
